/**
 * Mithila Art Studio — Cloudinary Asset Registry
 * Auto-generated by backend/scripts/uploadAssets.js
 *
 * IMPORTANT: This file maps logical asset keys to permanent Cloudinary URLs.
 * Never hotlink external image URLs in production — always use these keys.
 *
 * If an upload fails, a fallback placeholder is used and marked _needsUpload: true
 */

// ─── HELPER ──────────────────────────────────────────────────────────────────
// Import this file in components instead of hardcoding Cloudinary URLs.
// Usage: import { getAsset } from '../data/assets';
//        <img src={getAsset('art_madhubani_main')} />

let _cache = null;

function loadCache() {
  if (_cache) return _cache;
  try {
    // In production this JSON is generated by the upload script
    const data = require('./cloudinaryAssets.json');
    _cache = data;
  } catch (e) {
    _cache = {};
  }
  return _cache;
}

export function getAsset(key) {
  const cache = loadCache();
  const entry = cache[key];
  if (entry && entry.cloudinary_url) return entry.cloudinary_url;
  return null; // caller should use fallback
}

